mapper.select:
select * from xhbs_points_rule where is_deleted = 0
and (rule_name like concat('%', #{ruleName}, '%') or rule_code like concat('%', #{ruleName}, '%'))
and direction = #{direction}
and implementation_status = #{implementationStatus}
order by sort_order asc, id asc

select count(*) from xhbs_points_rule
where rule_code = #{ruleCode}
and id != #{excludeId}
